message.content:
You are implementing Task 5 of the Digital Loyalty Card App.

**Context:** Monorepo at C:\Users\User\loyalty-app. Database schema in supabase/migrations/001_initial_schema.sql defines 10 tables.

**TASK: Row Level Security (RLS) Policies**

Create `supabase/migrations/002_rls_policies.sql` with this EXACT content:

```sql
-- Enable RLS on all tables
alter table public.merchants enable row level security;
alter table public.loyalty_programs enable row level security;
alter table public.rewards enable row level security;
alter table public.qr_codes enable row level security;
alter table public.customers enable row level security;
alter table public.customer_cards enable row level security;
alter table public.transactions enable row level security;
alter table public.campaigns enable row level security;
alter table public.notifications enable row level security;
alter table public.referrals enable row level security;

-- MERCHANTS: owner can CRUD
create policy "Merchants: owner full access" on public.merchants
  for all using (auth.uid() = user_id);

-- LOYALTY PROGRAMS: merchant owner can CRUD, customers can read active
create policy "Programs: merchant owner full access" on public.loyalty_programs
  for all using (merchant_id in (select id from public.merchants where user_id = auth.uid()));

create policy "Programs: customers can read active" on public.loyalty_programs
  for select using (is_active = true);

-- REWARDS: merchant owner can CRUD, customers can read active
create policy "Rewards: merchant owner full access" on public.rewards
  for all using (program_id in (
    select lp.id from public.loyalty_programs lp
    join public.merchants m on m.id = lp.merchant_id
    where m.user_id = auth.uid()
  ));

create policy "Rewards: customers can read active" on public.rewards
  for select using (is_active = true);

-- QR CODES: merchant owner can CRUD
create policy "QR codes: merchant owner full access" on public.qr_codes
  for all using (merchant_id in (select id from public.merchants where user_id = auth.uid()));

-- CUSTOMERS: own profile only
create policy "Customers: own profile" on public.customers
  for all using (auth.uid() = id);

-- Also let merchants read their customers (via cards)
create policy "Customers: merchant can read" on public.customers
  for select using (
    id in (
      select cc.customer_id from public.customer_cards cc
      join public.loyalty_programs lp on lp.id = cc.program_id
      join public.merchants m on m.id = lp.merchant_id
      where m.user_id = auth.uid()
    )
  );

-- CUSTOMER CARDS: customer owns, merchant can read
create policy "Cards: customer full access" on public.customer_cards
  for all using (auth.uid() = customer_id);

create policy "Cards: merchant can read" on public.customer_cards
  for select using (
    program_id in (
      select lp.id from public.loyalty_programs lp
      join public.merchants m on m.id = lp.merchant_id
      where m.user_id = auth.uid()
    )
  );

-- TRANSACTIONS: customer can read own, merchant can read their programs'
create policy "Transactions: customer can read own" on public.transactions
  for select using (
    card_id in (select id from public.customer_cards where customer_id = auth.uid())
  );

create policy "Transactions: merchant can read" on public.transactions
  for select using (
    card_id in (
      select cc.id from public.customer_cards cc
      join public.loyalty_programs lp on lp.id = cc.program_id
      join public.merchants m on m.id = lp.merchant_id
      where m.user_id = auth.uid()
    )
  );

-- CAMPAIGNS: merchant owner can CRUD
create policy "Campaigns: merchant owner full access" on public.campaigns
  for all using (merchant_id in (select id from public.merchants where user_id = auth.uid()));

-- NOTIFICATIONS: customer can read own
create policy "Notifications: customer can read own" on public.notifications
  for select using (auth.uid() = customer_id);

create policy "Notifications: customer can update own" on public.notifications
  for update using (auth.uid() = customer_id);

-- REFERRALS: customer can read own
create policy "Referrals: own referrals" on public.referrals
  for all using (auth.uid() = referrer_id or auth.uid() = referred_id);
```

Then commit:
```bash
cd /c/Users/User/loyalty-app && git add . && git commit -m "feat: add Row Level Security policies for all tables"
```

